    id: toRestId(node.legacyResourceId || node.id),
    graphqlId: node.id,
    title: node.title || '',
    vendor: node.vendor || '',
    status: normalizeStatus(node.status),
    tags: Array.isArray(node.tags) ? node.tags.slice() : [],
